var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"오랜만이야, 승선을 환영하지. 맨션의 마담.","JPN":"久しぶりだな。乗船を歓迎する、マンションのマダム。","ENG":"Long time no see. Welcome aboard, Madam of the Mansion.","TWN":"好久不見，歡迎你，曼森的女主人。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"됐으니까 선실로 안내나 해. 소금기로 머리가 푸석거리기 전에.","JPN":"いいから船室に案内して。潮風のせいで髪の毛が痛む前に。","ENG":"Shut up and just show me to the cabins. All this salty air is going to dry out my hair.","TWN":"好了，快帶我到船艙吧，我頭髮都沒型了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"꼴불견이군.","JPN":"みっともないな。","ENG":"Ugh, you're ridiculous.","TWN":"真是無語。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그 나이 먹고 아직도 머릿결 타령이나 하는 거냐?","JPN":"その歳でまだ髪の毛なんかを気にしてんのか？","ENG":"You're still raving on about your hair at your age?","TWN":"都一把年紀了，還在意什麼髮型？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"오일 냄새나 맡고 다니던 정비공 주제에 분수도 모르고 나랑 말을 섞으려 드네?","JPN":"オイル臭い整備工のくせに、身の程も知らずに私に話しかけてるの？","ENG":"What does a grease monkey like you know about hair anyway?","TWN":"區區一個臭維修工，不知道分寸，竟敢和我搭話？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"매일 두르고 다니던 그 거지 같은 사막 전투복은 수용소에서 압수라도 당했니?","JPN":"いつものボロボロな砂漠用戦闘服は収容所で押収でもされたのかしら？","ENG":"And what happened to the ragged desert uniform you wore every day? Did they confiscate it at the penitentiary?","TWN":"妳每天穿著那破爛沙漠戰鬥服，是被集中營抓走了嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"하여간 보여줄 것도 없으면서 풀어헤치고 다니는 것부터 품위라곤 찾아볼 수가 없다니까.","JPN":"見せられるモノもないくせに見せっぱなしで、まったく品が感じられないんだから。","ENG":"For someone who likes to show so much skin, you've got nothing much to see, really. Such lack of class.","TWN":"也不知道妳為什麼每天都不把衣服扣上，真是沒品。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐라고?! 기계의 완벽함도 제대로 모르는 년이 뭐가 어째?","JPN":"はあ？　機械の完璧さもろくに知らないバカが何だと？","ENG":"What? What do you know, you dimwit? You don't even appreciate the perfection of machinery!","TWN":"什麼？！妳一個連機器的機都不會寫的臭婆娘還敢亂說？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"꽃이니 메이드니 하는 나약한 살덩이들에 둘러싸여서 기술 발전에도 못 따라오는 퇴물 주제에 허세만 부리긴!","JPN":"花だのメイドだの弱々しい肉体に囲まれて、技術発展にもついて来れない年代物のくせに見栄ばかり張りやがって！","ENG":"You just keep yourself pampered by those weak lumps of flesh you call flowers or maids or whatever!","TWN":"什麼花啊，女僕啊，天天被一群小女子包圍，連個技術都發展不出來的廢物，還敢說大話！"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"워, 워. 기껏 수용소에서 꺼내줬더니 만나자마자 싸우면 곤란해, 아가씨들.","JPN":"どうどう。せっかく収容所から出してやったのに、会ってすぐ喧嘩されても困るぞ、お嬢ちゃんたち。","ENG":"Come on now, ladies. I just got you out of jail. I can't have you fighting already.","TWN":"喂，喂，我把妳們從集中營救出來，可不是為了讓妳們吵架，小姐們。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"정 싸우고 싶으면 저기 물에 들어가서 싸우던가.","JPN":"喧嘩したいなら、あの海の中でやってくれ。","ENG":"If you really must fight, you could just jump into the water.","TWN":"如果妳們想吵，不如進水裡打一架吧。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>평의회</color> 멤버 두 명이 허우적거리면서 싸우는 광경이라니, 관람하는 재미가 쏠쏠하겠군.","JPN":"<color=#ffd34c>評議会</color>メンバー2人がじたばたしながら戦う光景って、観覧する側はさぞかし楽しいだろうな。","ENG":"Watching two members of <color=#ffd34c>the Council</color> catfight while trying to swim should be interesting.","TWN":"看兩個<color=#ffd34c>評議會</color>成員在打架的樣子，想想就覺得有趣。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"누가 싸운대? 시비를 걸어오길래 대답했을 뿐이야.","JPN":"喧嘩？　因縁をつけてきたから答えただけよ。","ENG":"Who said anything about fighting? Besides, she started it.","TWN":"誰吵架了？我只是看有人搬弄是非，便說了一句而已。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"금속의 아름다움을 아는 내가 참도록 하지. 내 기생충들은 물을 싫어하니까.","JPN":"ちっ……ここは金属の美しさを知る俺が我慢してやる。うちの寄生虫は水が嫌いだからな。","ENG":"I'll be the bigger person, as someone who truly appreciates the beauty of metal. My parasites hate water, after all.","TWN":"知道金屬之美的我暫且忍一忍吧，我的寄生蟲可是很討厭水的。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하하. 이것 봐. 사이 좋은 모습이 훨씬 더 보기 좋잖아.","JPN":"ハハハ、ほら。仲良くしたほうがずっといいぞ。","ENG":"Hah hah, see? It's so much better when we all get along.","TWN":"哈哈，妳們這樣可比吵吵鬧鬧好多了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"잔말은 됐어. 평의회는 왜 소집한 거야?","JPN":"無駄話はその辺にしてちょうだい。それで、評議会はどうして召集したの？","ENG":"Enough with the small talk. Why did you convene the Council?","TWN":"廢話少說，但你怎麼突然想起要召開評議會？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MMASTER_NPC_NULL_NULL","text":{"KOREA":"나오는 데 거들어 준 건 고맙지만 이걸 빌미로 괜한 간섭을 하는 건 사절이야.","JPN":"脱出を手伝ってくれたのはありがたいけど、それを口実に余計な干渉をするのはお断りよ。","ENG":"As much as I appreciate you busting me out of there, I'm going to pass if you're going to use that as leverage to intervene in my life.","TWN":"雖然我很感謝你出手相救，但我不希望你以此作為藉口隨意進行干涉。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MMASTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};